const updateScripts=({content:t,originalContent:e={}})=>{const s=t.scripts;if(!s)return e;if(Object.entries(s).some(([t,e])=>"string"!=typeof t||"string"!=typeof e))throw Object.assign(new TypeError("package.json scripts should be a key-value pair of strings."),{code:"ESCRIPTSINVALID"});return{...e,scripts:{...s}}};module.exports=updateScripts;